import { LogoutOutlined } from "@ant-design/icons";
import Tippy from "@tippyjs/react";
import classNames from "classnames";
import { observer } from "mobx-react-lite";
import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";

import { GMMenu } from "@/components/GMMenu";
import { useGameReactions } from "@/hooks/useGameReactions.ts";
import { useMockStreams } from "@/hooks/useMockStreams.ts";
import { routes } from "@/router/routs.ts";
import { rootStore } from "@/store/rootStore.ts";

import styles from "./GameBottomBar.module.scss";
import { GameReactionsBar } from "./GameReactionsBar";
import { SelfMediaControlsBar } from "./SelfMediaControlsBar";

type GameBottomBarProps = {
  isJoinedToGame: boolean;
  videoDeviceId: string;
  audioInputDeviceId: string;
  audioOutputDeviceId: string;
  onSelectVideoDevice: (id: string) => void;
  onSelectAudioInputDevice: (id: string) => void;
  onSelectAudioOutputDevice: (id: string) => void;
  onOpenVideoConfig: () => void;
  onOpenAudioConfig: () => void;
};

export const GameBottomBar = observer(
  ({
    isJoinedToGame,
    videoDeviceId,
    audioInputDeviceId,
    audioOutputDeviceId,
    onSelectVideoDevice,
    onSelectAudioInputDevice,
    onSelectAudioOutputDevice,
    onOpenVideoConfig,
    onOpenAudioConfig,
  }: GameBottomBarProps) => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const { isIGM } = rootStore;
    const { sendReaction } = useGameReactions();
    const { allTracks } = useMockStreams();

    const [isVisible, setIsVisible] = useState(false);
    const { isNight } = rootStore.gamesStore.gameFlow;

    useEffect(() => {
      if (isJoinedToGame && allTracks.length > 0 && (isIGM || !isNight)) {
        setIsVisible(true);
      } else {
        setIsVisible(false);
      }
    }, [isJoinedToGame, allTracks.length, isNight, isIGM]);

    return (
      <div
        className={classNames(styles.bottomBar, {
          [styles.bottomBarVisible]: isVisible,
        })}
      >
        <SelfMediaControlsBar
          videoDeviceId={videoDeviceId}
          audioInputDeviceId={audioInputDeviceId}
          audioOutputDeviceId={audioOutputDeviceId}
          onSelectVideoDevice={onSelectVideoDevice}
          onSelectAudioInputDevice={onSelectAudioInputDevice}
          onSelectAudioOutputDevice={onSelectAudioOutputDevice}
          onOpenVideoConfig={onOpenVideoConfig}
          onOpenAudioConfig={onOpenAudioConfig}
        />

        <div className={styles.divider} />

        <GameReactionsBar sendReaction={sendReaction} />

        <div className={styles.divider} />

        {isIGM ? (
          <GMMenu />
        ) : (
          <Tippy
            content={t("gmMenu.leaveGame")}
            delay={[500, 0]}
            theme="role-tooltip"
          >
            <button
              className={classNames(styles.controlBtn, styles.danger)}
              onClick={() => navigate(routes.home)}
              aria-label={t("gmMenu.leaveGame")}
            >
              <LogoutOutlined />
            </button>
          </Tippy>
        )}
      </div>
    );
  }
);

GameBottomBar.displayName = "GameBottomBar";

import { FileSearchOutlined, LogoutOutlined } from "@ant-design/icons";
import Tippy from "@tippyjs/react";
import classNames from "classnames";
import { observer } from "mobx-react-lite";
import { useCallback, useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";

import { GMMenu } from "@/components/GMMenu";
import { ModalNames } from "@/components/Modals/Modal.types.ts";
import { useGameReactions } from "@/hooks/useGameReactions.ts";
import { useMockStreams } from "@/hooks/useMockStreams.ts";
import { routes } from "@/router/routs.ts";
import { rootStore } from "@/store/rootStore.ts";

import styles from "./GameBottomBar.module.scss";
import { GameReactionsBar } from "./GameReactionsBar";
import { SelfMediaControlsBar } from "./SelfMediaControlsBar";

type GameBottomBarProps = {
  isJoinedToGame: boolean;
  videoDeviceId: string;
  audioInputDeviceId: string;
  audioOutputDeviceId: string;
  onSelectVideoDevice: (id: string) => void;
  onSelectAudioInputDevice: (id: string) => void;
  onSelectAudioOutputDevice: (id: string) => void;
  onOpenVideoConfig: () => void;
  onOpenAudioConfig: () => void;
};

export const GameBottomBar = observer(
  ({
    isJoinedToGame,
    videoDeviceId,
    audioInputDeviceId,
    audioOutputDeviceId,
    onSelectVideoDevice,
    onSelectAudioInputDevice,
    onSelectAudioOutputDevice,
    onOpenVideoConfig,
    onOpenAudioConfig,
  }: GameBottomBarProps) => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const { isIGM, gamesStore, modalStore } = rootStore;
    const { sendReaction } = useGameReactions();
    const { allTracks } = useMockStreams();

    const [isVisible, setIsVisible] = useState(false);
    const { isNight } = gamesStore.gameFlow;
    const hasLastNightResults = !!gamesStore.lastNightActionLogs;

    const onViewNightResults = useCallback(() => {
      const { lastNightActionLogs } = gamesStore;

      if (!lastNightActionLogs) return;

      modalStore.openModal(ModalNames.NightResultsModal, {
        nightActionLogs: lastNightActionLogs,
      });
    }, [gamesStore, modalStore]);

    useEffect(() => {
      if (isJoinedToGame && allTracks.length > 0 && (isIGM || !isNight)) {
        setIsVisible(true);
      } else {
        setIsVisible(false);
      }
    }, [isJoinedToGame, allTracks.length, isNight, isIGM]);

    return (
      <div
        className={classNames(styles.bottomBar, {
          [styles.bottomBarVisible]: isVisible,
        })}
      >
        <SelfMediaControlsBar
          videoDeviceId={videoDeviceId}
          audioInputDeviceId={audioInputDeviceId}
          audioOutputDeviceId={audioOutputDeviceId}
          onSelectVideoDevice={onSelectVideoDevice}
          onSelectAudioInputDevice={onSelectAudioInputDevice}
          onSelectAudioOutputDevice={onSelectAudioOutputDevice}
          onOpenVideoConfig={onOpenVideoConfig}
          onOpenAudioConfig={onOpenAudioConfig}
        />

        <div className={styles.divider} />

        <GameReactionsBar sendReaction={sendReaction} />

        <div className={styles.divider} />

        {isIGM ? (
          <>
            <GMMenu />

            {!isNight && hasLastNightResults && (
              <Tippy
                content={t("gmMenu.viewNightResults")}
                delay={[500, 0]}
                theme="role-tooltip"
              >
                <button
                  className={styles.controlBtn}
                  onClick={onViewNightResults}
                  aria-label={t("gmMenu.viewNightResults")}
                >
                  <FileSearchOutlined />
                </button>
              </Tippy>
            )}
          </>
        ) : (
          <Tippy
            content={t("gmMenu.leaveGame")}
            delay={[500, 0]}
            theme="role-tooltip"
          >
            <button
              className={classNames(styles.controlBtn, styles.danger)}
              onClick={() => navigate(routes.home)}
              aria-label={t("gmMenu.leaveGame")}
            >
              <LogoutOutlined />
            </button>
          </Tippy>
        )}
      </div>
    );
  }
);

GameBottomBar.displayName = "GameBottomBar";

import { observer } from "mobx-react-lite";
import { useEffect } from "react";

import { useCustomVideo } from "@/hooks/useCustomVideo.ts";
import { useVideoSettings } from "@/hooks/useVideoSettings.ts";

type VideoConfigLoaderProps = {
  originalStream: MediaStream | null;
  gameId: string;
  onNeedConfig: () => void;
};

export const VideoConfigLoader = observer(
  ({ originalStream, gameId, onNeedConfig }: VideoConfigLoaderProps) => {
    const { getSavedSettings } = useVideoSettings(gameId);
    const { applySettings } = useCustomVideo(originalStream);

    useEffect(() => {
      if (!originalStream) return;

      const savedSettings = getSavedSettings();

      if (savedSettings) {
        applySettings(savedSettings);
      } else {
        onNeedConfig();
      }
    }, [originalStream, getSavedSettings, applySettings, onNeedConfig]);

    return null;
  }
);

VideoConfigLoader.displayName = "VideoConfigLoader";

import { useCallback, useState } from "react";
import { useNavigate } from "react-router-dom";

import { updateGameGM } from "@/api/game/api.ts";
import { useFinishGameMutation, useRestartGameMutation } from "@/api/game/queries.ts";
import { ModalNames } from "@/components/Modals/Modal.types.ts";
import { useAddTestUsers } from "@/hooks/useAddTestUsers.ts";
import { useBatchMediaControls } from "@/hooks/useBatchMediaControls.ts";
import { useMockStreams } from "@/hooks/useMockStreams.ts";
import { routes } from "@/router/routs.ts";
import { rootStore } from "@/store/rootStore.ts";

export const useGMMenu = () => {
  const navigate = useNavigate();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const { gamesStore, usersStore, isIGM } = rootStore;
  const { activeGameId, activeGameGm, gameFlow } = gamesStore;
  const { myId } = usersStore;

  const { unmuteAll, muteAllExceptGM, disableAllCamerasExceptGM, enableAllCameras } = useBatchMediaControls();

  const { mockStreamsEnabled, handleToggleMockStreams } = useMockStreams();
  const { mutate: restartGame } = useRestartGameMutation();
  const { mutate: finishGame } = useFinishGameMutation();
  // TODO: remove — temporary for layout stress-testing
  const { onAddTestUsers, isAddingTestUsers } = useAddTestUsers();

  const onMakeMeGM = useCallback(async () => {
    if (!activeGameId || !myId) return;

    try {
      await updateGameGM({
        gameId: activeGameId,
        userId: myId,
      });
      setIsMenuOpen(false);
    } catch (error) {
      console.error("Failed to set you as GM:", error);
    }
  }, [activeGameId, myId]);

  const onToggleMockStreams = useCallback(() => {
    handleToggleMockStreams();
    setIsMenuOpen(false);
  }, [handleToggleMockStreams]);

  const onMuteAll = useCallback(() => {
    muteAllExceptGM(activeGameGm);
    setIsMenuOpen(false);
  }, [activeGameGm, muteAllExceptGM]);

  const onUnmuteAll = useCallback(() => {
    unmuteAll();
    setIsMenuOpen(false);
  }, [unmuteAll]);

  const onDisableAllCameras = useCallback(() => {
    disableAllCamerasExceptGM(activeGameGm);
    setIsMenuOpen(false);
  }, [activeGameGm, disableAllCamerasExceptGM]);

  const onEnableAllCameras = useCallback(() => {
    enableAllCameras();
    setIsMenuOpen(false);
  }, [enableAllCameras]);

  const onRestartGame = useCallback(() => {
    if (!activeGameId) return;

    setIsMenuOpen(false);
    rootStore.modalStore.openModal(ModalNames.ConfirmRestartModal, {
      onConfirm: () => restartGame(activeGameId),
    });
  }, [activeGameId, restartGame]);

  const onFinishGame = useCallback(() => {
    if (!activeGameId) return;

    finishGame(activeGameId);
    setIsMenuOpen(false);
  }, [activeGameId, finishGame]);

  const onLeaveGame = useCallback(() => {
    setIsMenuOpen(false);
    navigate(routes.home);
  }, [navigate]);

  const onViewNightResults = useCallback(() => {
    const { lastNightActionLogs } = gamesStore;

    if (!lastNightActionLogs) return;

    setIsMenuOpen(false);
    rootStore.modalStore.openModal(ModalNames.NightResultsModal, {
      nightActionLogs: lastNightActionLogs,
    });
  }, [gamesStore]);

  return {
    isMenuOpen,
    setIsMenuOpen,
    isIGM,
    mockStreamsEnabled,
    gameFlow,
    onMakeMeGM,
    onToggleMockStreams,
    onMuteAll,
    onUnmuteAll,
    onDisableAllCameras,
    onEnableAllCameras,
    onRestartGame,
    onFinishGame,
    onLeaveGame,
    onViewNightResults,
    hasLastNightResults: !!gamesStore.lastNightActionLogs,
    // TODO: remove — temporary for layout stress-testing
    onAddTestUsers,
    isAddingTestUsers,
  };
};

